+   4. Components
+   -------------------------------------------------------------------------- */
+
+/* Stripe-style adaptive glass
+   NOTE: no permanent will-change here — it creates unnecessary compositor
+   layers on every glass element. Let the browser promote only when needed. */
+.glass-modern {
+  background: rgba(5, 18, 5, 0.8);
+  backdrop-filter: blur(8px);
+  -webkit-backdrop-filter: blur(8px);
+  border: 1px solid rgba(255, 255, 255, 0.05);
+  box-shadow: var(--shadow-lg);
+}
+
+/* Kinetic Hover Effect */
+.kinetic-card {
+  transition: all var(--duration-normal) var(--ease-stripe);
+}
+
+.kinetic-card:hover {
+  transform: translateY(-4px) scale(1.01);
+  border-color: rgba(34, 197, 94, 0.3);
+  box-shadow: var(--shadow-franken);
+}
+
+/* Living Gradient Text */
+.text-animate-green {
+  background: linear-gradient(
+    to right,
+    #4ade80,
+    #bef264,
+    #22c55e,
+    #4ade80
+  );
+  background-size: 300% auto;
+  -webkit-background-clip: text;
+  background-clip: text;
+  color: transparent;
+  animation: textGradient 8s linear infinite;
+}
+
+@keyframes textGradient {
+  to { background-position: 300% center; }
+}
